import{_ as i,o as a,c as s,ag as c}from"./chunks/framework.CAXxHpAX.js";const y=JSON.parse('{"title":"民族民主运动","description":"","frontmatter":{},"headers":[],"relativePath":"notes/note-30.md","filePath":"notes/note-30.md"}'),l={name:"notes/note-30.md"};function v(r,d,e,o,t,n){return a(),s("div",null,[...d[0]||(d[0]=[c('<h1 id="民族民主运动" tabindex="-1">民族民主运动 <a class="header-anchor" href="#民族民主运动" aria-label="Permalink to &quot;民族民主运动&quot;">​</a></h1><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>民族民主运动</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">第一次工业革命：</span></p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">印度民族大起义：</span>反抗英国，章西女王（封建王公）、失败，印度民族意识的觉醒。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">拉丁美洲独立运动：</span>玻利瓦尔、圣马丁（南美解放者、民族资产阶级）。玻利瓦尔解放了哥伦比亚、委内瑞拉和厄瓜多尔；圣马丁解放了阿根廷、智利、秘鲁。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">中国太平天国运动：</span>1851-1864年，洪秀全（最大规模的农民起义），失败。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">第一次世界大战：</span></p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">印度非暴力不合作运动：</span>反英，甘地（民族资产阶级）。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">埃及华夫脱运动：</span>反英，扎格鲁尔（民族资产阶级）、有条件承认埃及独立。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">墨西哥卡德纳斯改革：</span>卡德纳斯（民族资产阶级），巩固墨西哥资产阶级革命成果。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">第二次世界大战：</span></p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">亚洲：</span></p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>1</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>9</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>5</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>5、印尼、万隆会议（周恩来提出求同存异方针）、参与国为亚非国家。第一次没有西方殖民主义国家参加的亚非会议。标志着发展中国家作为一只新兴独立政治力量登上国家舞台。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">非洲：</span>1960年，非洲年，17个非洲国家独立。1990年，纳米比亚独立，标志着所有非洲国家摆脱殖民主义的枷锁。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">拉美：</span>反美，巴拿马运河，1999年收回运河主权。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>反美，古巴，卡斯特罗，走上了社会主义道路。</p></div><div class="circle-overlay"></div></div></div>',19)])])}const b=i(l,[["render",v]]);export{y as __pageData,b as default};
